('business:5-3-revenue-costs-profit-loss:match:fbd02bcb', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Revenue”?", "options": ["Costs that do not change when output changes — e.g. rent, insurance, salaries.", "Costs that change directly with output — e.g. raw materials, packaging, hourly wages.", "Fixed costs plus variable costs (TC = TFC + TVC).", "The income received from sales, calculated as quantity sold × selling price."]}'::jsonb, '{"answer": 3, "explain": "“Revenue” means: The income received from sales, calculated as quantity sold × selling price."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:1805adaf', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fixed Costs”?", "options": ["Costs that change directly with output — e.g. raw materials, packaging, hourly wages.", "Costs that do not change when output changes — e.g. rent, insurance, salaries.", "Fixed costs plus variable costs (TC = TFC + TVC).", "The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product."]}'::jsonb, '{"answer": 1, "explain": "“Fixed Costs” means: Costs that do not change when output changes — e.g. rent, insurance, salaries."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:05a2da08', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Variable Costs”?", "options": ["Fixed costs plus variable costs (TC = TFC + TVC).", "The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product.", "The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Costs that change directly with output — e.g. raw materials, packaging, hourly wages."]}'::jsonb, '{"answer": 3, "explain": "“Variable Costs” means: Costs that change directly with output — e.g. raw materials, packaging, hourly wages."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:78f9c563', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total Costs”?", "options": ["The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product.", "Fixed costs plus variable costs (TC = TFC + TVC).", "The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Revenue minus cost of sales — profit before running costs are deducted."]}'::jsonb, '{"answer": 1, "explain": "“Total Costs” means: Fixed costs plus variable costs (TC = TFC + TVC)."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:8599bf9b', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cost of Sales”?", "options": ["The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Revenue minus cost of sales — profit before running costs are deducted.", "Gross profit minus expenses — the most accurate measure of overall business performance.", "The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product."]}'::jsonb, '{"answer": 3, "explain": "“Cost of Sales” means: The direct cost of producing the goods sold — e.g. materials, bought-in stock, direct labour to make the product."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:37edbd71', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Expenses”?", "options": ["The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising.", "Revenue minus cost of sales — profit before running costs are deducted.", "Gross profit minus expenses — the most accurate measure of overall business performance.", "When total costs are greater than total revenue."]}'::jsonb, '{"answer": 0, "explain": "“Expenses” means: The ongoing running costs of the business — rent, wages, insurance, heating, lighting, advertising."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:b61e68f7', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gross Profit”?", "options": ["Gross profit minus expenses — the most accurate measure of overall business performance.", "When total costs are greater than total revenue.", "(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "Revenue minus cost of sales — profit before running costs are deducted."]}'::jsonb, '{"answer": 3, "explain": "“Gross Profit” means: Revenue minus cost of sales — profit before running costs are deducted."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:94dda9d5', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net Profit”?", "options": ["Gross profit minus expenses — the most accurate measure of overall business performance.", "When total costs are greater than total revenue.", "(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs."]}'::jsonb, '{"answer": 0, "explain": "“Net Profit” means: Gross profit minus expenses — the most accurate measure of overall business performance."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:b5921e15', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Loss”?", "options": ["(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs.", "When total costs are greater than total revenue.", "(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments."]}'::jsonb, '{"answer": 2, "explain": "“Loss” means: When total costs are greater than total revenue."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:2e36e318', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gross Profit Margin”?", "options": ["(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs.", "(Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling.", "(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments.", "Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue."]}'::jsonb, '{"answer": 1, "explain": "“Gross Profit Margin” means: (Gross Profit ÷ Revenue) × 100 — measures profit efficiency from buying and selling."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:ed38b8e9', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net Profit Margin”?", "options": ["(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments.", "Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue.", "(Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs.", "The income received from sales, calculated as quantity sold × selling price."]}'::jsonb, '{"answer": 2, "explain": "“Net Profit Margin” means: (Net Profit ÷ Revenue) × 100 — the most accurate profitability ratio, accounting for all costs."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:1d45d559', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Average Rate of Return”?", "options": ["Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue.", "(Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments.", "The income received from sales, calculated as quantity sold × selling price.", "Costs that do not change when output changes — e.g. rent, insurance, salaries."]}'::jsonb, '{"answer": 1, "explain": "“Average Rate of Return” means: (Average Annual Profit ÷ Cost of Investment) × 100 — compares the profitability of different investments."}'::jsonb),
('business:5-3-revenue-costs-profit-loss:match:b3eb9456', 'business', 'business:5-3-revenue-costs-profit-loss', '5.3 Revenue, Costs, Profit', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profitability Ratios”?", "options": ["The income received from sales, calculated as quantity sold × selling price.", "Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue.", "Costs that do not change when output changes — e.g. rent, insurance, salaries.", "Costs that change directly with output — e.g. raw materials, packaging, hourly wages."]}'::jsonb, '{"answer": 1, "explain": "“Profitability Ratios” means: Calculations such as GPM and NPM that measure how efficiently a business generates profit from revenue."}'::jsonb),
('business:5-4-break-even:exam:f03bff8a', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q1", "question": "A manufacturer that makes and sells more than its break-even quantity will:", "options": ["Have insufficient revenue to cover costs", "Make a profit", "Need to improve its quality control", "Require an overdraft"], "hint": "Think about what happens to profit when total revenue exceeds total costs.", "starter": "The correct answer is B because selling beyond break-even means..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Make a profit</h5><p><strong>Why B is correct:</strong> Once a business sells more units than its break-even output, total revenue exceeds total costs — a profit is made on every additional unit sold.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Incorrect:</strong> Insufficient revenue to cover costs describes what happens BELOW break-even. Above break-even, revenue more than covers all costs.</li><li><strong>C — Incorrect:</strong> Quality control is unrelated to the break-even quantity. Selling above break-even says nothing about product quality.</li><li><strong>D — Incorrect:</strong> An overdraft relates to a cash flow problem, not to selling above the break-even point. A business can be profitable but still have cash flow issues.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:72a78416', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q4", "question": "How many hours of gardening will Amaya need to do to start to make a profit?", "options": ["1,059 hours", "1,385 hours", "2,340 hours", "3,060 hours"], "caseStudy": "Amaya is a gardener. She charges £15 per hour. Her fixed costs are £18,000 per annum. Her variable costs are £2 per hour.", "hint": "Contribution = selling price − variable cost per hour. Break-even = fixed costs ÷ contribution. Remember to round UP your answer.", "starter": "Contribution per hour = £15 − £2 = £13\nBreak-even = £18,000 ÷ £13 = ...\nRound UP to ... hours"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — 1,385 hours</h5><p><strong>Working:</strong></p><ul><li>Contribution = £15 − £2 = £13 per hour</li><li>Break-even = £18,000 ÷ £13 = 1,384.6 → round UP = <strong>1,385 hours</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (1,059):</strong> Incorrect — results from using the wrong contribution figure, e.g. dividing by £17 (adding price + VC rather than subtracting).</li><li><strong>C (2,340):</strong> Incorrect — results from an error in dividing by the wrong number, possibly using the selling price alone as the denominator in a partial calculation.</li><li><strong>D (3,060):</strong> Incorrect — results from dividing fixed costs only by the variable cost (£18,000 ÷ £2 × something), ignoring the correct contribution formula entirely.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:f4e2b0bd', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q5", "question": "How many one-hour lessons will Kim need to give before making a profit?", "options": ["389 lessons", "467 lessons", "584 lessons", "2,334 lessons"], "caseStudy": "Kim is a driving instructor. Kim charges £30 for a one-hour lesson. Her fixed costs are £14,000 per annum. The variable cost for a one-hour lesson is £6.", "hint": "Contribution = price per lesson − variable cost. Break-even = fixed costs ÷ contribution. Remember to round UP.", "starter": "Contribution per lesson = £30 − £6 = £24\nBreak-even = £14,000 ÷ £24 = ...\nRound UP to ... lessons"}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — 584 lessons</h5><p><strong>Working:</strong></p><ul><li>Contribution = £30 − £6 = £24 per lesson</li><li>Break-even = £14,000 ÷ £24 = 583.3 → round UP = <strong>584 lessons</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (389):</strong> Incorrect — results from using an incorrect contribution figure.</li><li><strong>B (467):</strong> Incorrect — results from dividing by the wrong number in the formula.</li><li><strong>D (2,334):</strong> Incorrect — results from dividing fixed costs by the variable cost only (£14,000 ÷ £6 = 2,333.3), completely ignoring the selling price in the contribution calculation.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:0e542abb', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q8", "question": "If Andrea paints and sells 50 portraits a year, total costs are estimated to be:", "options": ["£1,075 per year", "£4,750 per year", "£12,075 per year", "£15,750 per year"], "caseStudy": "Andrea specialises in painting portraits. She estimates that:\n• variable costs for labour are £52 per portrait\n• variable costs for materials are £23 per portrait\n• fixed costs are £1,000 per month", "hint": "Convert monthly fixed costs to annual first (× 12). Then calculate total variable costs (VC per portrait × 50). Finally, add fixed and variable costs together.", "starter": "Annual fixed costs = £1,000 × 12 = £12,000\nVC per portrait = £52 + £23 = £75\nTotal VC = £75 × 50 = £3,750\nTotal costs = £12,000 + £3,750 = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — £15,750 per year</h5><p><strong>Working:</strong></p><ul><li>Annual fixed costs = £1,000 × 12 = £12,000</li><li>Variable cost per portrait = £52 + £23 = £75</li><li>Total variable costs = £75 × 50 = £3,750</li><li>Total costs = £12,000 + £3,750 = <strong>£15,750</strong></li></ul><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A (£1,075):</strong> Incorrect — results from simply adding £52 + £23 + £1,000 without multiplying by 50 portraits or converting monthly to annual FC. Completely ignores the quantities involved.</li><li><strong>B (£4,750):</strong> Incorrect — results from using the monthly fixed cost (£1,000) instead of the annual figure (£12,000), giving £3,750 + £1,000 = £4,750.</li><li><strong>C (£12,075):</strong> Incorrect — likely used only one variable cost component (e.g. just £52 or £23) rather than adding both together, then added the annual FC of £12,000.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:98af4d76', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q9", "question": "At break-even a firm''s total revenue equals its:", "options": ["Fixed costs only", "Gross profit", "Net profit", "Total costs"], "hint": "At break-even, the business makes no profit and no loss. What does this tell you about the relationship between revenue and costs?", "starter": "At break-even, TR = ..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Total costs</h5><p>At break-even, total revenue equals total costs (TR = TC). The business makes neither a profit nor a loss.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Fixed costs only:</strong> Total revenue must cover BOTH fixed AND variable costs to break even. Fixed costs alone understates the total costs the business must cover.</li><li><strong>B — Gross profit:</strong> Gross profit = revenue − cost of sales. At break-even, net profit is zero, but gross profit may still exist. Gross profit is not the same as total costs.</li><li><strong>C — Net profit:</strong> If TR equalled net profit, there would be no costs at all — this is clearly impossible for any real business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:exam:0322e36e', 'business', 'business:5-4-break-even', '5.4 Break-even', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Which of the following is a limitation of break-even analysis?", "options": ["It cannot be used to estimate the profit a business is likely to make", "It cannot factor in seasonal pricing and price discounts", "It cannot show how much a business needs to sell to cover its costs", "It cannot show the level of profit or loss at a range of outputs"], "hint": "Think about what break-even CANNOT do. Eliminate options A, C, and D by checking whether break-even CAN actually do those things.", "starter": "The correct answer is B because break-even analysis assumes..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — It cannot factor in seasonal pricing and price discounts</h5><p>Break-even assumes a single, fixed selling price throughout. It cannot account for price changes such as seasonal discounts, promotional pricing, or variable pricing strategies — all of which affect actual revenue differently at different points in time.</p><p><strong>Why the others are wrong:</strong></p><ul><li><strong>A — Incorrect:</strong> Break-even CAN be used to estimate profit at different output levels — by comparing TR with TC at any point on the graph or table.</li><li><strong>C — Incorrect:</strong> Showing how much a business must sell to cover its costs IS the core purpose and main strength of break-even analysis.</li><li><strong>D — Incorrect:</strong> By comparing TR and TC at various outputs (on a graph or in a table), break-even CAN show the level of profit or loss across a full range of outputs.</li></ul><p><strong>Examiner''s Comment:</strong> Many candidates chose A because they saw the word \"estimate\" and assumed it must be a limitation. This is a common trap — always read all four options carefully before selecting. Each MCQ is worth 1 mark and deserves at least a minute of careful thought.</p></div>", "modelAnswer": ""}'::jsonb),
('business:5-4-break-even:mcq:328ae7f4', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "What is the break-even quantity?", "options": ["The output level at which a business maximises its profit", "The output level at which total revenue equals total costs", "The output level at which fixed costs equal variable costs", "The output level at which a business earns its highest revenue"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even is the point where total revenue exactly equals total costs, so the business makes neither a profit nor a loss."}'::jsonb),
('business:5-4-break-even:mcq:f4f8b70a', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A manufacturer that makes and sells MORE than its break-even quantity will:", "options": ["Have insufficient revenue to cover costs", "Make a profit", "Need to improve its quality control", "Require an overdraft"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Once a business sells beyond its break-even output, total revenue exceeds total costs, resulting in a profit. Options A and D are what happens BELOW break-even. Option C is unrelated to break-even."}'::jsonb),
('business:5-4-break-even:mcq:0a3f8962', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "At break-even, a firm''s total revenue equals its:", "options": ["Fixed costs only", "Gross profit", "Net profit", "Total costs"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. At break-even, TR = TC. The business covers ALL costs (fixed AND variable), meaning there is zero profit and zero loss."}'::jsonb),
('business:5-4-break-even:mcq:2fde6fe0', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Amaya is a gardener. She charges £15 per hour. Her fixed costs are £18,000 per annum. Her variable costs are £2 per hour. How many hours does Amaya need to work to START making a profit?", "options": ["1,059 hours", "1,385 hours", "2,340 hours", "3,060 hours"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — 1,385 hours. Contribution = £15 − £2 = £13. Break-even = £18,000 ÷ £13 = 1,384.6 → round UP to 1,385 hours. Always round up because you cannot break even on a fraction of a unit."}'::jsonb),
('business:5-4-break-even:mcq:f16edf6c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Kim is a driving instructor charging £30 per lesson. Fixed costs are £14,000 per year. Variable costs are £6 per lesson. How many lessons must Kim give before making a profit?", "options": ["389 lessons", "467 lessons", "584 lessons", "2,334 lessons"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — 584 lessons. Contribution = £30 − £6 = £24. Break-even = £14,000 ÷ £24 = 583.3 → round UP to 584. Option D results from dividing by variable cost only (÷ £6), ignoring the selling price."}'::jsonb),
('business:5-4-break-even:mcq:0322e36e', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Which of the following is a limitation of break-even analysis?", "options": ["It cannot be used to estimate the profit a business is likely to make", "It cannot factor in seasonal pricing and price discounts", "It cannot show how much a business needs to sell to cover its costs", "It cannot show the level of profit or loss at a range of outputs"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even assumes a single fixed price. It cannot account for seasonal pricing, promotional discounts, or variable pricing — all of which affect actual revenue. Options A, C, and D are all things break-even CAN do."}'::jsonb),
('business:5-4-break-even:mcq:fad7487c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A business has fixed costs of £20,000, a selling price of £50, and variable costs of £30 per unit. What is its break-even output?", "options": ["400 units", "667 units", "1,000 units", "1,500 units"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — 1,000 units. Contribution = £50 − £30 = £20. Break-even = £20,000 ÷ £20 = 1,000 units."}'::jsonb),
('business:5-4-break-even:mcq:7d606c4b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A business''s actual output is 5,000 units and its break-even output is 3,500 units. What is the margin of safety?", "options": ["1,500 units", "3,500 units", "5,000 units", "8,500 units"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — 1,500 units. Margin of safety = actual sales − break-even sales = 5,000 − 3,500 = 1,500 units."}'::jsonb),
('business:5-4-break-even:mcq:93a177f6', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Carlton Press Ltd has fixed costs of £30,000, variable costs of £2 per booklet, and sells each booklet at £5. What is the break-even output?", "options": ["5,000 booklets", "10,000 booklets", "15,000 booklets", "20,000 booklets"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — 10,000 booklets. Contribution = £5 − £2 = £3. Break-even = £30,000 ÷ £3 = 10,000 booklets."}'::jsonb),
('business:5-4-break-even:mcq:d219560c', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Which of these may cause a break-even forecast to turn out to be incorrect?", "options": ["The number of competitors in the market remains the same", "The business sells all its goods at its planned price", "The cost of importing raw materials increases", "Workers accept the planned rise in wages"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. If raw material costs increase, variable costs rise unexpectedly — making the original break-even forecast inaccurate. Options A, B, and D all describe scenarios where things go exactly as planned, so the forecast would remain valid."}'::jsonb),
('business:5-4-break-even:mcq:194f9c33', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "A business will make a LOSS if:", "options": ["Its revenues are greater than its costs", "It uses its revenues to pay off all its debts", "It sells less than its break-even output", "It has to take out an overdraft"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A business makes a loss when it sells fewer units than its break-even output — meaning total costs exceed total revenue. An overdraft is a cash flow issue; it does not automatically mean the business is making a loss."}'::jsonb),
('business:5-4-break-even:mcq:11b684ec', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "If Carlton Press Ltd (break-even = 10,000) sells 20,000 books, what is its margin of safety?", "options": ["5,000 booklets", "10,000 booklets", "15,000 booklets", "20,000 booklets"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — 10,000 booklets. Margin of safety = actual sales − break-even output = 20,000 − 10,000 = 10,000 booklets."}'::jsonb),
('business:5-4-break-even:mcq:dc4a8a93', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "If a business''s fixed costs INCREASE, what happens to its break-even output?", "options": ["It decreases because there are more costs to spread", "It increases because more units must be sold to cover the higher costs", "It stays the same because variable costs are unchanged", "It decreases because contribution per unit rises"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Break-even = FC ÷ contribution. If fixed costs rise (numerator increases) while contribution stays the same, the result is a higher break-even output — the business must sell more units to cover all its costs."}'::jsonb),
('business:5-4-break-even:mcq:0a301562', 'business', 'business:5-4-break-even', '5.4 Break-even', 'mcq', 'mcq', 1, '{"question": "Andrea paints portraits. Labour VC = £52, materials VC = £23 per portrait, fixed costs = £1,000 per month. If she paints 50 portraits per year, total annual costs are:", "options": ["£1,075 per year", "£4,750 per year", "£12,075 per year", "£15,750 per year"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — £15,750. Annual FC = £1,000 × 12 = £12,000. VC per portrait = £52 + £23 = £75. TVC = £75 × 50 = £3,750. Total costs = £12,000 + £3,750 = £15,750. Many students forget to convert monthly FC to annual."}'::jsonb),
('business:5-4-break-even:tf:b5f0811b', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even is the point at which total revenue equals total costs."}'::jsonb, '{"answer": true, "explain": "TRUE. At break-even, TR = TC exactly. The business covers all its costs but makes neither a profit nor a loss. This is the core definition."}'::jsonb),
('business:5-4-break-even:tf:14c6ccca', 'business', 'business:5-4-break-even', '5.4 Break-even', 'tf', 'tf', 1, '{"question": "Break-even output is measured in pounds (£), not units."}'::jsonb, '{"answer": false, "explain": "FALSE. Break-even output is always measured in UNITS (e.g., 12,500 toys or 30 cakes). Writing a £ sign instead of units will cost you a mark in the exam."}'::jsonb)
